const express = require('express');
const session = require('express-session');
const twilio = require('twilio');

// Twilio Account Settings
const accountSid = 'your_account_sid';
const authToken = 'your_auth_token';
const client = new twilio(accountSid, authToken);

// Session Store
const MemoryStore = session.MemoryStore;
const store = new MemoryStore();

// Express App Setup
const app = express();
app.use(session({
  secret: 'secret_key',
  resave: false,
  saveUninitialized: true,
  store: store
}));

// Generate Random Code
function generateCode() {
  const code = Math.floor(Math.random() * (999999 - 100000 + 1)) + 100000;
  return code.toString();
}

// Send SMS Verification Code
app.post('/send-verification-code', (req, res) => {
  const phoneNumber = req.body.phoneNumber;
  if (!phoneNumber || !/^\d+$/.test(phoneNumber)) {
    return res.status(400).json({ error: 'Invalid phone number' });
  }

  const code = generateCode();
  client.messages
    .create({
      from: 'your_twilio_phone_number',
      to: phoneNumber,
      body: `Your verification code is ${code}`
    })
    .then((message) => {
      req.session.verificationCode = code;
      res.json({ message: 'Verification code sent successfully' });
    })
    .done();
});

// Verify User Input
app.post('/verify-input', (req, res) => {
  const inputCode = req.body.inputCode;
  if (!inputCode || !/^\d+$/.test(inputCode)) {
    return res.status(400).json({ error: 'Invalid verification code' });
  }

  const storedCode = req.session.verificationCode;
  if (storedCode !== inputCode) {
    return res.status(401).json({ error: 'Verification code does not match' });
  }

  delete req.session.verificationCode;
  res.json({ message: 'Verification successful' });
});

// Start Server
const port = 3000;
app.listen(port, () => {
  console.log(`Server started on port ${port}`);
});